// Notion v2.2: Properties als property_feldname
// Termine aufteilen in NEU und ABGELAUFEN, dann x Kunden flatten
var items = $input.all();
var flat = [];
var now = new Date();
var cutoff = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);

for (var i = 0; i < items.length; i++) {
  var props = items[i].json;
  var notionPageId = props.id;

  var datumObj = props.property_datum;
  var datumRaw = null;
  if (datumObj && datumObj.start) {
    datumRaw = datumObj.start;
  } else if (typeof datumObj === 'string' && datumObj.length >= 10) {
    datumRaw = datumObj;
  }
  if (!datumRaw) continue;

  var terminDate = new Date(datumRaw);

  var confluenceSync = props.property_confluence_sync === true
    || props.property_confluencesync === true;

  var typ = null;
  if (!confluenceSync && terminDate >= cutoff) {
    typ = 'NEU';
  } else if (confluenceSync && terminDate < cutoff) {
    typ = 'ABGELAUFEN';
  }
  if (!typ) continue;

  var titel = props.property_titel || props.name || 'Kein Titel';
  var ort = props.property_ort || '';

  var datumIso = datumRaw.substring(0, 10);
  var dp = datumIso.split('-');
  var datumStr = dp[2] + '.' + dp[1] + '.' + dp[0];

  var uhrzeitStr = '';
  var tIdx = datumRaw.indexOf('T');
  if (tIdx !== -1) {
    uhrzeitStr = datumRaw.substring(tIdx + 1, tIdx + 6);
  }

  var kundenRaw = props.property_kunden || [];
  var kundenIds = Array.isArray(kundenRaw) ? kundenRaw : [kundenRaw];
  if (kundenIds.length === 0) continue;

  var confluenceTerminIDs = props.property_confluence_termin_i_ds
    || props.property_confluenceterminids
    || props.property_confluence_termin_ids
    || '';

  var rowId = notionPageId.replace(/-/g, '');

  for (var j = 0; j < kundenIds.length; j++) {
    var kundePageId = kundenIds[j];
    if (!kundePageId) continue;
    flat.push({
      json: {
        notionPageId: notionPageId,
        titel: titel,
        ort: ort,
        datumStr: datumStr,
        uhrzeitStr: uhrzeitStr,
        datumIso: datumIso,
        kundePageId: kundePageId,
        confluenceTerminIDs: confluenceTerminIDs,
        rowId: rowId,
        typ: typ
      }
    });
  }
}

return flat;

// Panel-Suche mit 4 Methoden + Debug-Kontext im Fehlerfall
var page = $json;
var d = $('Set: Daten zusammenfuehren').item.json;

var esc = function(s) {
  return String(s || '').replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
};

var rowId = d.rowId;
var spaceKey = d.spaceKey;
var terminRowId = rowId + '-' + spaceKey;
var datumIso = d.datumIso;
var datumStr = d.datumStr;
var uhrzeitStr = d.uhrzeitStr || '';
var titel = esc(d.titel);
var ort = esc(d.ort);

var pageId = page.id || '';
var pageTitle = page.title || '';
var currentVersion = (page.version && page.version.number) ? page.version.number : 1;
var html = (page.body && page.body.storage && page.body.storage.value)
  ? page.body.storage.value : '';

var marker = '<!--tid:' + terminRowId + ' dt:' + datumIso + '-->';

// --- Alle <ac:rich-text-body> Abschnitte sammeln ---
var rtbOpen = '<ac:rich-text-body>';
var rtbClose = '</ac:rich-text-body>';
var allSections = [];
var sp = 0;
while (true) {
  var oi = html.indexOf(rtbOpen, sp);
  if (oi === -1) break;
  var s = oi + rtbOpen.length;
  var e = html.indexOf(rtbClose, s);
  if (e === -1) break;
  allSections.push({ start: s, end: e });
  sp = e + rtbClose.length;
}

// --- Titel suchen (6 Encodings) ---
var panelTitles = [
  'N\u00e4chste Termine',
  'N&auml;chste Termine',
  'N&#228;chste Termine',
  'N&#xE4;chste Termine',
  'N&#xe4;chste Termine',
  'Termine'
];
var titleIdx = -1;
for (var ti = 0; ti < panelTitles.length; ti++) {
  titleIdx = html.indexOf(panelTitles[ti]);
  if (titleIdx !== -1) break;
}

var bodyStart = -1;
var bodyEnd = -1;

// Methode 1: erster rich-text-body NACH dem Titel-Text
if (titleIdx !== -1) {
  for (var si = 0; si < allSections.length; si++) {
    if (allSections[si].start > titleIdx) {
      bodyStart = allSections[si].start;
      bodyEnd = allSections[si].end;
      break;
    }
  }
}

// Methode 2: Abschnitt mit bestehenden tid-Markern
if (bodyStart === -1) {
  for (var si2 = 0; si2 < allSections.length; si2++) {
    if (html.substring(allSections[si2].start, allSections[si2].end).indexOf('<!--tid:') !== -1) {
      bodyStart = allSections[si2].start;
      bodyEnd = allSections[si2].end;
      break;
    }
  }
}

// Methode 3: Abschnitt mit Datum+Uhrzeit-Header
if (bodyStart === -1) {
  for (var si3 = 0; si3 < allSections.length; si3++) {
    var sc3 = html.substring(allSections[si3].start, allSections[si3].end);
    if (sc3.indexOf('>Datum<') !== -1 && sc3.indexOf('>Uhrzeit<') !== -1) {
      bodyStart = allSections[si3].start;
      bodyEnd = allSections[si3].end;
      break;
    }
  }
}

// Methode 4: <ac:layout-cell> das den Titel enthaelt
if (bodyStart === -1 && titleIdx !== -1) {
  var cellOpen = '<ac:layout-cell>';
  var cellClose = '</ac:layout-cell>';
  var cp = 0;
  while (true) {
    var ci = html.indexOf(cellOpen, cp);
    if (ci === -1) break;
    var cs = ci + cellOpen.length;
    var ce = html.indexOf(cellClose, cs);
    if (ce === -1) break;
    if (cs <= titleIdx && titleIdx < ce) {
      bodyStart = cs;
      bodyEnd = ce;
      break;
    }
    cp = ce + cellClose.length;
  }
}

// Kein Panel gefunden: Fehler mit Debug-Kontext
if (bodyStart === -1 || bodyEnd === -1) {
  var termIdx = html.indexOf('Termine');
  var ctx = termIdx !== -1
    ? html.substring(Math.max(0, termIdx - 200), Math.min(html.length, termIdx + 500))
    : 'Termine_nicht_im_HTML';
  throw new Error('Panel nicht gefunden. pageId:' + pageId
    + ' rtb_sections:' + allSections.length
    + ' titleIdx:' + titleIdx
    + ' || HTML_KONTEXT: ' + ctx);
}

// --- Panel-Body neu aufbauen ---
var bodyContent = html.substring(bodyStart, bodyEnd);
var bodyParts = bodyContent.split('<tr>');
var existingRows = [];
for (var idx = 1; idx < bodyParts.length; idx++) {
  if (bodyParts[idx].indexOf('<!--tid:') !== -1) {
    existingRows.push(bodyParts[idx]);
  }
}

var newRow = marker + '<td>' + datumStr + '</td><td>' + uhrzeitStr + '</td><td>' + titel + '</td><td>' + ort + '</td></tr>';
existingRows.push(newRow);

existingRows.sort(function(a, b) {
  var getDate = function(row) {
    var m = row.match(/<!--tid:\S+ dt:(\d{4}-\d{2}-\d{2})-->/);
    return m ? new Date(m[1]).getTime() : 0;
  };
  return getDate(a) - getDate(b);
});

var headerRow = '<tr><th>Datum</th><th>Uhrzeit</th><th>Titel</th><th>Ort</th></tr>';
var dataRowsHtml = existingRows.map(function(r) { return '<tr>' + r; }).join('');
var newBodyContent = '<table><tbody>' + headerRow + dataRowsHtml + '</tbody></table>';

html = html.substring(0, bodyStart) + newBodyContent + html.substring(bodyEnd);

var prev = d.confluenceTerminIDs || '';
var newEntry = spaceKey + ':' + terminRowId;
var updatedTerminIDs = prev ? prev + ',' + newEntry : newEntry;

return {
  json: {
    pageId: pageId,
    pageTitle: pageTitle,
    newVersion: currentVersion + 1,
    updatedHtml: html,
    notionPageId: d.notionPageId,
    updatedTerminIDs: updatedTerminIDs
  }
};

// Panel-Suche mit 4 Methoden + Debug-Kontext im Fehlerfall
var page = $json;
var d = $('Set: Daten zusammenfuehren').item.json;

var spaceKey = d.spaceKey;
var rowId = d.rowId;
var terminRowId = rowId + '-' + spaceKey;

