var bodyContent = html.substring(bodyStart, bodyEnd);
var bodyParts = bodyContent.split('<tr>');
var markerToDelete = '<!--tid:' + storedRowId + ' ';
var remainingRows = [];
for (var idx = 1; idx < bodyParts.length; idx++) {
